
.card {
  width: 100%;
  max-width: 720px;
  background-color: var(--c-mint-cream);
  border: 3px solid var(--c-granite);
  box-shadow: 5px 5px 0px rgba(60, 73, 63, 0.16);
  display: flex;
  flex-direction: column;
  font-family: var(--font-archive);
  color: var(--c-granite);
  font-size: 13px;
  line-height: 1.35;
  margin: 0 auto;
}

.empty-state {
  text-align: center;
  color: var(--c-grey-olive);
  padding: 12px;
  font-style: italic;
  font-size: 0.85rem;
}

// 女主角
.heroine-list {
  padding: 6px;
}

.heroine-item {
  padding: 6px 8px;
  border-bottom: 1px dashed var(--c-ash-grey);
  &:last-child { border-bottom: none; }
}

.heroine-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 4px;
}

.heroine-name {
  font-weight: bold;
  font-size: 0.9rem;
}

.heroine-stage {
  font-size: 0.75rem;
  padding: 1px 6px;
  background: var(--c-ash-grey);
  &.stage-trust { background: var(--c-celadon); color: var(--c-granite); }
  &.stage-bond { background: var(--c-gold); color: #fff; }
}

.heroine-detail {
  display: flex;
  gap: 6px;
  flex-wrap: wrap;
}

.detail-tag {
  font-size: 0.75rem;
  padding: 1px 5px;
  border: 1px solid var(--c-grey-olive);
  &.tag-bond { background: var(--c-gold); border-color: var(--c-gold); color: #fff; }
  &.tag-quest { background: var(--c-sky); border-color: var(--c-sky); }
}

// 功法
.gongfa-section {
  padding: 8px;
}

.gongfa-main {
  display: flex;
  gap: 8px;
  padding: 6px;
  background: var(--c-ash-grey);
  margin-bottom: 6px;
}

.gongfa-item {
  display: flex;
  gap: 6px;
  padding: 4px 6px;
  align-items: center;
  border-bottom: 1px dashed var(--c-ash-grey);
  &:last-child { border-bottom: none; }
}

.gongfa-name {
  font-weight: bold;
  flex: 1;
}

.detail-label {
  font-weight: bold;
  color: var(--c-grey-olive);
}

.detail-value {
  flex: 1;
}

// 任务
.quest-section {
  padding: 10px;
}

.quest-row {
  display: flex;
  padding: 5px 0;
  border-bottom: 1px dashed var(--c-ash-grey);
  &:last-child { border-bottom: none; }
}

.quest-label {
  width: 60px;
  font-weight: bold;
  color: var(--c-grey-olive);
  flex-shrink: 0;
}

.quest-value {
  flex: 1;
}

// 已结交NPC
.npc-list {
  padding: 6px;
}

.npc-item {
  padding: 6px 8px;
  border-bottom: 1px dashed var(--c-ash-grey);
  &:last-child { border-bottom: none; }
}

.npc-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 4px;
}

.npc-name {
  font-weight: bold;
  font-size: 0.9rem;
}

.npc-detail {
  display: flex;
  gap: 6px;
}
