
.empty-state {
  text-align: center;
  color: var(--c-grey-olive);
  padding: 12px;
  font-style: italic;
  font-size: 0.85rem;
}

.category-list {
  padding: 6px;
}

.category-block {
  margin-bottom: 4px;
  border: 1.5px solid var(--c-grey-olive);
}

.category-header {
  display: flex;
  align-items: center;
  padding: 5px 8px;
  background: var(--c-mint-cream);
  cursor: pointer;
  user-select: none;
  gap: 6px;
  &:hover { background: var(--c-ash-grey); }
}

.cat-icon {
  width: 20px;
  height: 20px;
  background: var(--c-sky);
  border: 1.5px solid var(--c-granite);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 0.6rem;
  font-weight: bold;
  flex-shrink: 0;
}

.cat-name {
  flex: 1;
  font-weight: bold;
  font-size: 0.8rem;
}

.cat-count {
  background: var(--c-granite);
  color: #fff;
  padding: 0 5px;
  font-size: 0.65rem;
}

.cat-arrow {
  font-size: 0.7rem;
  color: var(--c-grey-olive);
  width: 14px;
  text-align: center;
}

.category-items {
  padding: 3px 6px 6px 34px;
}

.inv-item {
  display: flex;
  align-items: center;
  padding: 3px 0;
  border-bottom: 1px dashed var(--c-ash-grey);
  gap: 6px;
  font-size: 0.82rem;
  &:last-child { border-bottom: none; }
}

.inv-name { flex: 1; }
.inv-qty { color: var(--c-granite); font-weight: bold; }
.inv-grade { font-size: 0.7rem; color: var(--c-grey-olive); }
